import{_ as s,c as a,o as t,a3 as l}from"./chunks/framework.LNmJnetQ.js";const h=JSON.parse('{"title":"Q&A - html","description":"","frontmatter":{"title":"Q&A - html"},"headers":[],"relativePath":"flow/fe/iq-html.md","filePath":"flow/fe/iq-html.md"}'),n={name:"flow/fe/iq-html.md"},p=l(`<details class="details custom-block"><summary>什么是BOM，什么是DOM？</summary><ul><li><p>DOM（Document Object Model——文档对象模型）是用来呈现以及与任意 HTML 或 XML 文档交互的 API。DOM 是载入到浏览器中的文档模型，以节点树的形式来表现文档，每个节点代表文档的构成部分。它允许运行在浏览器中的代码访问文件中的节点并与之交互。节点可以被创建，移动或修改。事件监听器可以被添加到节点上并在给定事件发生时触发。DOM 并不是天生就被规范好了的，它是浏览器开始实现JavaScript时才出现的。这个传统的 DOM 有时会被称为 DOM 0。</p></li><li><p>BOM（Browser Object Model——浏览器对象模型）提供与浏览器交互的方法和接口（即访问和操作浏览器）。window（访问浏览器窗口的一个接口，又是ECMAScript规定的Global对象） , navigator（浏览器详细信息） ，location（浏览器所加载页面的详细信息），screen（用户显示器分辨率详细信息），history（用户上网的历史记录）</p></li></ul></details><details class="details custom-block"><summary>简单描述从输入网址到页面显示的过程？</summary><p>域名解析 –&gt; 发起TCP的3次握手 –&gt; 建立TCP连接后发起http请求 –&gt; 服务器响应http请求，浏览器得到html代码 –&gt; 浏览器解析html代码，并请求html代码中的资源（如js、css、图片等） –&gt; 浏览器对页面进行渲染呈现给用户</p></details><details class="details custom-block"><summary>图片格式的选择？</summary><p>是否动画 -&gt; gif</p><p>是否控制监听动画状态 -&gt; svg</p><p>是否要求背景透明 -&gt; png</p><p>WEBP 目标是减少文件大小, 能同时支持无损压缩和有损压缩。</p><p>SVG是一种用XML定义的语言，用来描述二维矢量及矢量/栅格图形。SVG提供了3种类型的图形对象：矢量图形（例如：由直线和曲线组成的路径）、图象、文本。</p></details><details class="details custom-block"><summary>前端跨页面通信，你知道哪些方法？</summary><p>LocalStorage</p><p>SessionStorage</p><p>window.postMessage</p><p>SharedWorker</p><p>IndexedDB</p><p>WebSockets</p><p>BroadcastChannel只能用于同源的页面之间进行通信，而postMessage却可以用于任何的页面之间的通信。</p></details><details class="details custom-block"><summary>DOM树</summary><p>发起请求（响应头） -&gt; 网络进程 -&gt; content-type 判断文件类型 -&gt; 字节流 -&gt; html解析器</p><p>字节流（Bytes）-&gt; 分词器（Tokens）-&gt; 生成节点（Node）-&gt; DOM</p></details><details class="details custom-block"><summary>行内元素有哪些？块级元素有哪些？ 空(void)元素有那些 ？</summary><p>HTML 中的行内元素（inline elements）通常用于在一行内显示，不会独占一行的空间。常见的行内元素有：span，strong，em，a，img，input</p><p>块级元素（block-level elements）通常会独占一行的空间，并且会在前后创建换行。常见的块级元素有：div，p，h1- h6，ul，ol，li，table</p><p>空元素（void elements）是指没有闭合标签的元素。它们在 HTML 中没有内容，只有一个开启标签。常见的空元素有：br，img，meta，link，hr</p></details><details class="details custom-block"><summary>html和css中的图片加载与渲染规则是什么样的 ？</summary><p>解析HTML，构成DOM树 -&gt; 解析加载的样式，构建样式规则树 -&gt; 加载JavaScript，执行JavaScript代码 -&gt; DOM树和样式规则树进行匹配，构成渲染树 -&gt; 计算元素位置进行页面布局 -&gt; 绘制页面，最终在浏览器中呈现</p></details><details class="details custom-block"><summary>script 标签为什么建议放在 body 标签的底部 ？</summary><p>因为浏览器在渲染html的时候是从上到下执行的，当遇到js文件的时候就会停止当前页面的渲染，转而去下载js文件。如果将script标签放在头部，在文件很大的情况下将导致首屏加载时间延长，影响用户体验。可以将script标签放在body的底部，或者通过defer、async属性将js文件转为异步加载。</p></details><details class="details custom-block"><summary>什么是HTML5，以及和HTML的区别是什么 ？</summary><p>HTML5是HTML的新标准，其主要目标是无需任何额外的插件如Flash等，就可以传输所有内容。它囊括了动画、视频、丰富的图形用户界面等。</p><p>HTML5声明简单（<code>&lt;!DOCTYPE html&gt;</code>），在语义上却有很大的优势。提供了一些新的标签，比如：<code>&lt;header&gt;&lt;article&gt;&lt;footer&gt;</code>。</p><p>DOCTYPE声明于文档最前面，告诉浏览器以何种方式来渲染页面。</p></details><details class="details custom-block"><summary>Node 和 Element 是什么关系 ？</summary><p>Element 继承于 Node，具有Node的方法，同时又拓展了很多自己的特有方法。Node的一些方法，返回值为Node，比如说文本节点，注释节点之类的，而Element的一些方法，返回值则一定是Element。</p></details><details class="details custom-block"><summary>从输入url，到页面的画面展示的过程 ？</summary><p>1、首先，在浏览器地址栏中输入url</p><p>2、浏览器先查看浏览器缓存-系统缓存-路由器缓存，如果缓存中有，会直接在屏幕中显示页面内容。若没有，则跳到第三步操作。</p><p>3、在发送http请求前，需要域名解析(DNS解析)，解析获取相应的IP地址。</p><p>4、浏览器向服务器发起tcp连接，与浏览器建立tcp三次握手。</p><p>5、握手成功后，浏览器向服务器发送http请求，请求数据包。</p><p>6、服务器处理收到的请求，将数据返回至浏览器</p><p>7、浏览器收到HTTP响应</p><p>8、读取页面内容，浏览器渲染，解析html源码</p><p>9、生成Dom树、解析css样式、js交互,渲染显示页面</p></details><details class="details custom-block"><summary>白屏性能优化 ？</summary><p>DNS解析优化</p><p>服务端处理优化</p><p>浏览器下载、解析、渲染页面优化 (样式，标签，js文件，图片)</p></details><details class="details custom-block"><summary>如何控制 input 输入框的输入字数 ？</summary><p><code>&lt;input maxlength=&quot;5&quot; /&gt;</code>，另外还可以通过监听 οninput 事件，对输入值进行处理。</p></details><details class="details custom-block"><summary>在选择图片后，通过浏览器预览待上传的图片 ？</summary><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>function imgPreview(img) {</span></span>
<span class="line"><span> document.querySelector(&quot;img&quot;).src = window.URL.cteateObejectURL(img.files[0]);</span></span>
<span class="line"><span>}</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>function imgPreview(img) {</span></span>
<span class="line"><span>    const reader = new FileReader();</span></span>
<span class="line"><span>    reader.onload = function () {</span></span>
<span class="line"><span>        document.querySelector(&quot;img&quot;).src = imgFile;</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>    reader.readAsDataURL(img.files[0]);</span></span>
<span class="line"><span>}</span></span></code></pre></div></details><details class="details custom-block"><summary>怎么实现“点击回到顶部”的功能 ？</summary><ul><li>锚点</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>&lt;body style=&quot;height:1080px;&quot;&gt;</span></span>
<span class="line"><span>    &lt;div id=&quot;top&quot;&gt;&lt;/div&gt;</span></span>
<span class="line"><span>    &lt;a href=&quot;#top&quot; style=&quot;position:fixed;right:0;bottom:0&quot;&gt;回到顶部&lt;/a&gt;</span></span>
<span class="line"><span>&lt;/body&gt;</span></span></code></pre></div><ul><li>scrollTop</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>&lt;body style=&quot;height:1080px;&quot;&gt;</span></span>
<span class="line"><span>    &lt;button id=&quot;top&quot; style=&quot;position:fixed;right:0;bottom:0&quot;&gt;回到顶部&lt;/button&gt;</span></span>
<span class="line"><span>    &lt;script&gt;</span></span>
<span class="line"><span>        top.onclick = function(){</span></span>
<span class="line"><span>          document.body.scrollTop = document.documentElement.scrollTop = 0;</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>    &lt;/script&gt;</span></span>
<span class="line"><span>&lt;/body&gt;</span></span></code></pre></div><ul><li>scrollTo</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>&lt;body style=&quot;height:2000px;&quot;&gt;</span></span>
<span class="line"><span>    &lt;button id=&quot;top&quot; style=&quot;position:fixed;right:0;bottom:0&quot;&gt;回到顶部&lt;/button&gt;</span></span>
<span class="line"><span>    &lt;script&gt;</span></span>
<span class="line"><span>        top.onclick = function(){</span></span>
<span class="line"><span>          scrollTo(0,0);</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>    &lt;/script&gt;</span></span>
<span class="line"><span>&lt;/body&gt;</span></span></code></pre></div><ul><li>scrollBy</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>&lt;body style=&quot;height:2000px;&quot;&gt;</span></span>
<span class="line"><span>    &lt;button id=&quot;top&quot; style=&quot;position:fixed;right:0;bottom:0&quot;&gt;回到顶部&lt;/button&gt;</span></span>
<span class="line"><span>    &lt;script&gt;</span></span>
<span class="line"><span>        top.onclick = function(){</span></span>
<span class="line"><span>            const top = document.body.scrollTop || document.documentElement.scrollTop</span></span>
<span class="line"><span>            scrollBy(0,-top);</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>    &lt;/script&gt;</span></span>
<span class="line"><span>&lt;/body&gt;</span></span></code></pre></div><ul><li>scrollIntoView</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>&lt;body style=&quot;height:2000px;&quot;&gt;</span></span>
<span class="line"><span>    &lt;div id=&quot;target&quot;&gt;&lt;/div&gt;</span></span>
<span class="line"><span>    &lt;button id=&quot;top&quot; style=&quot;position:fixed;right:0;bottom:0&quot;&gt;回到顶部&lt;/button&gt;</span></span>
<span class="line"><span>    &lt;script&gt;</span></span>
<span class="line"><span>        top.onclick = function(){</span></span>
<span class="line"><span>            target.scrollIntoView();</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>    &lt;/script&gt;</span></span>
<span class="line"><span>&lt;/body&gt;</span></span></code></pre></div></details><details class="details custom-block"><summary>SPA应用怎么进行SEO ？</summary><p>SSR 服务端渲染，预渲染</p></details><details class="details custom-block"><summary>如何实现SEO优化 ？</summary><p>SEO（Search Engine Optimization），搜索引擎优化是一种利用搜索引擎的搜索规则来提高目前网站在有关搜索引擎内的自然排名的方式。</p><p>原理：爬行和抓取 -&gt; 建立索引 -&gt; 搜索词处理 -&gt; 排序</p><ul><li>内部优化</li></ul><ol><li><p>META 标签优化：例如：TITLE，KEYWORDS，DESCRIPTION （TDK）等的优化</p></li><li><p>内部链接的优化，包括相关性链接（Tag 标签），锚文本链接，各导航链接，及图片链接</p></li><li><p>网站内容更新：每天保持站内的更新(主要是文章的更新等)</p></li><li><p>服务器端渲染（SSR）</p></li></ol><ul><li>外部优化</li></ul><ol><li><p>外部链接类别：博客、论坛、B2B、新闻、分类信息、贴吧、知道、百科、相关信息网等尽量保持链接的多样性</p></li><li><p>外链运营：每天添加一定数量的外部链接，使关键词排名稳定提升。</p></li><li><p>外链选择：与一些和你网站相关性比较高,整体质量比较好的网站交换友情链接,巩固稳定关键词排名</p></li></ol></details><details class="details custom-block"><summary>DNS 预解析是什么？怎么实现 ?</summary><p>减少DNS请求次数，缩短DNS解析时间dns-prefetch。</p><p>dns-prefetch(DNS预获取)是前端网络性能优化的一种措施。它根据浏览器定义的规则，提前解析之后可能会用到的域名，使解析结果缓存到系统缓存中，缩短DNS解析时间，进而提高网站的访问速度。</p><p><code>&lt;link rel=&quot;dns-prefetch&quot; href=&quot;https://baidu.com/&quot;&gt; </code></p><p>解析过程: 浏览器缓存 -&gt; 系统缓存 -&gt; 路由器缓存 -&gt; ISP(运营商)DNS缓存 -&gt; 根域名服务器 -&gt; 顶级域名服务器 -&gt; 主域名服务器</p><p>TTL(Time-To-Live)，就是一条域名解析记录在DNS服务器中的存留时间。浏览器DNS缓存的时间跟DNS服务器返回的TTL值无关, 它的缓存时间取决于浏览器自身设置。浏览器DNS缓存的时间跟DNS服务器返回的TTL值无关, 它的缓存时间取决于浏览器自身设置。国内和国际上很多平台的TTL值都是以秒为单位的，很多的默认值都是3600，也就是默认缓存1小时。</p><p>dns-prefetch最大的缺点就是使用它太多。过多的预获取会导致过量的DNS解析，对网络是一种负担。</p><p>最佳实践：</p><ul><li><p>dns-prefetch 仅对跨域域上的 DNS查找有效，因此请避免使用它来指向相同域。这是因为，到浏览器看到提示时，您站点域背后的IP已经被解析。</p></li><li><p>除了link 还可以通过使用 HTTP链接字段将 dns-prefetch（以及其他资源提示）指定为 HTTP标头。</p></li><li><p>考虑将 dns-prefetch 与 preconnect(预连接)提示配对。</p></li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>&lt;link rel=&quot;preconnect&quot; href=&quot;https://fonts.gstatic.com/&quot; crossorigin&gt;</span></span>
<span class="line"><span>&lt;link rel=&quot;dns-prefetch&quot; href=&quot;https://fonts.gstatic.com/&quot;&gt;</span></span></code></pre></div><p>tips: 如果页面需要建立与许多第三方域的连接，则将它们预先连接会适得其反。 preconnect 提示最好仅用于最关键的连接。对于其他的，只需使用 <code>&lt;link rel=&quot;dns-prefetch&quot;&gt;</code> 即可节省第一步的时间DNS查找。</p></details><details class="details custom-block"><summary>Canvas和SVG有什么区别 ？</summary><p>SVG可缩放矢量图形（Scalable Vector Graphics）是基于可扩展标记语言XML描述的2D图形的语言，SVG基于XML就意味着SVG DOM中的每个元素都是可用的，可以为某个元素附加Javascript事件处理器。在 SVG 中，每个被绘制的图形均被视为对象。如果 SVG 对象的属性发生变化，那么浏览器能够自动重现图形:</p><ul><li>不依赖分辨率</li><li>支持事件处理器</li><li>最适合带有大型渲染区域的应用程序（比如谷歌地图）</li><li>复杂度高会减慢渲染速度（任何过度使用 DOM 的应用都不快）</li><li>不适合游戏应用</li></ul><p>Canvas是画布，通过Javascript来绘制2D图形，是逐像素进行渲染的。其位置发生改变，就会重新进行绘制:</p><ul><li>依赖分辨率</li><li>不支持事件处理器</li><li>弱的文本渲染能力</li><li>能够以 .png 或 .jpg 格式保存结果图像</li><li>最适合图像密集型的游戏，其中的许多对象会被频繁重绘</li></ul></details><details class="details custom-block"><summary>HTML5的离线储存怎么使用，它的工作原理是什么 ？</summary><p>离线存储指的是在用户没有与因特网连接时，可以正常访问站点或应用，在用户与因特网连接时，更新用户机器上的缓存文件。HTML5的离线存储是基于一个新建的 .appcache 文件的缓存机制，通过这个文件上的解析清单离线存储资源，这些资源就会像cookie一样被存储了下来。之后当网络在处于离线状态下时，浏览器会通过被离线存储的数据进行页面展示。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>&lt;html lang=&quot;en&quot; manifest=&quot;index.manifest&quot;&gt;</span></span></code></pre></div><p>在 cache.manifest 文件中编写需要离线存储的资源：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>CACHE MANIFEST</span></span>
<span class="line"><span>    #v0.11</span></span>
<span class="line"><span>    CACHE:</span></span>
<span class="line"><span>    js/app.js</span></span>
<span class="line"><span>    css/style.css</span></span>
<span class="line"><span>    NETWORK:</span></span>
<span class="line"><span>    resourse/logo.png</span></span>
<span class="line"><span>    FALLBACK:</span></span>
<span class="line"><span>    / /offline.html</span></span></code></pre></div></details><details class="details custom-block"><summary>img的srcset属性的作⽤ ？</summary><p>响应式页面中经常用到根据屏幕密度设置不同的图片。这时就用到了 img 标签的srcset属性。srcset属性用于设置不同屏幕密度下，img 会自动加载不同的图片。用法如下：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>&lt;img src=&quot;image-128.png&quot; srcset=&quot;image-256.png 2x&quot; /&gt;</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>&lt;img src=&quot;image-128.png&quot;</span></span>
<span class="line"><span>  srcset=&quot;image-128.png 128w, image-256.png 256w, image-512.png 512w&quot;</span></span>
<span class="line"><span>  sizes=&quot;(max-width: 360px) 340px, 128px&quot; /&gt;</span></span></code></pre></div><p>其中srcset指定图片的地址和对应的图片质量。sizes用来设置图片的尺寸零界点。对于 srcset 中的 w 单位，可以理解成图片质量。如果可视区域小于这个质量的值，就可以使用。浏览器会自动选择一个最小的可用图片。</p></details><details class="details custom-block"><summary>如何禁止input展示输入的历史记录？</summary><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>&lt;input type=&quot;text&quot;  autocomplete=&quot;off&quot; /&gt;</span></span></code></pre></div></details><details class="details custom-block"><summary>页面生命周期 ?</summary><p>HTML 页面的生命周期包含三个重要事件：</p><ul><li>DOMContentLoaded —— 浏览器已完全加载 HTML，并构建了 DOM 树，但像 <code>&lt;img&gt;</code> 和样式表之类的外部资源可能尚未加载完成。(DOM 已经就绪，因此处理程序可以查找 DOM 节点，并初始化接口。)</li><li>load —— 浏览器不仅加载完成了 HTML，还加载完成了所有外部资源：图片，样式等。(外部资源已加载完成，样式已被应用，图片大小也已知了。)</li><li>beforeunload/unload —— 当用户正在离开页面时。(用户正在离开：我们可以检查用户是否保存了更改，并询问他是否真的要离开; 用户几乎已经离开了，但是我们仍然可以启动一些操作，例如发送统计数据。)</li></ul></details><details class="details custom-block"><summary>iconfont是什么？有什么优缺点？</summary><p>优点：</p><ul><li>可以方便地将任何 CSS 效果应用于它们。</li><li>因为它们是矢量图形，所以它们是可伸缩的。这意味着我们可以在不降低质量的情况下伸缩它们。</li><li>我们只需要发送一个或少量 HTTP 请求来加载它们，而不是像图片，可能需要多个 HTTP 请求。</li><li>由于尺寸小，它们加载速度快。</li><li>它们在所有浏览器中都得到支持（甚至支持到 IE6）。</li></ul><p>缺点：</p><ul><li>不能用来显示复杂图像</li><li>通常只限于一种颜色，除非应用一些 CSS 技巧</li><li>字体图标通常是根据特定的网格设计的，例如 16x16, 32×32, 48×48等。如果由于某种原因将网格系统改为25×25，可能不会得到清晰的结果</li></ul></details><details class="details custom-block"><summary>mete标签中的viewport 有什么用 ？</summary><p>viewport 是用户网页的可视区域。一个常用的针对移动网页优化过的页面的 viewport meta 标签大致如下：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>&lt;meta name=&quot;viewport&quot; content=&quot;width=device-width, initial-scale=1.0&quot;&gt;</span></span></code></pre></div><ul><li>width：控制 viewport 的大小，可以指定的一个值，如 600，或者特殊的值，如 device-width 为设备的宽度（单位为缩放为 100% 时的 CSS 的像素）。</li><li>height：和 width 相对应，指定高度。</li><li>initial-scale：初始缩放比例，也即是当页面第一次 load 的时候缩放比例。</li><li>maximum-scale：允许用户缩放到的最大比例。</li><li>minimum-scale：允许用户缩放到的最小比例。</li><li>user-scalable：用户是否可以手动缩放。</li></ul></details><details class="details custom-block"><summary>webSocket如何兼容低浏览器 ？</summary><ul><li>Adobe Flash Socket；</li><li>ActiveX HTMLFile (IE) ；</li><li>基于 multipart 编码发送 XHR；</li><li>基于长轮询的 XHR；</li></ul></details><details class="details custom-block"><summary>HTML、XML、XHTML 的区别 ？</summary><ul><li>HTML：超文本标记语言，是语法较为松散的、不严格的Web语言；</li><li>XML：可扩展的标记语言，主要用于存储数据和结构，可扩展；</li><li>XHTML：可扩展的超文本标记语言，基于XML，作用与HTML类似，但语法更严格。</li></ul></details><details class="details custom-block"><summary>页面导入样式时，使用link和@import有什么区别 ？</summary><ul><li>link属于HTML标签，而@import是css提供的；</li><li>页面被加载时，link会同时被加载，而@import引用的css会等到页面被加载完再加载；</li><li>@import只在IE5以上才能识别，而link是XHTML标签，无兼容问题；</li><li>link方式的样式的权重高于@import的权重。</li></ul></details><details class="details custom-block"><summary>简述 html 页面渲染过程 ？</summary><p>URL对应的各种资源，通过浏览器渲染引擎的解析，输出可视化的图像。</p><p>解析HTML文件，创建DOM树 -&gt; 解析CSS,形成CSS对象模型 -&gt; 将CSS与DOM合并，构建渲染树（renderingtree）</p><p>Repaint(重绘)：重新构造样式，使元素呈现新的显示效果</p><p>Reflow(重排)：位置和大小信息改变</p></details><details class="details custom-block"><summary>HTML5 有哪些新特性 ？</summary><ul><li>新增语义化标签：nav、header、footer、aside、section、article</li><li>音频、视频标签：audio、video</li><li>数据存储：localStorage、sessionStorage</li><li>canvas（画布）、Geolocation（地理定位）、websocket（通信协议）</li><li>input标签新增属性：placeholder、autocomplete、autofocus、required</li><li>history API: go、forward、back、pushstate</li></ul></details><details class="details custom-block"><summary>HTML 标签中的 src 和 href 有什么区别 ？</summary><ul><li>href 是超文本引用，它是指向资源的位置，建立与目标文件的联系；</li><li>src 目的是把资源下载到页面中；</li></ul><p>浏览器解析 href 不会阻塞对文档的处理（这就是官方建议使用 link 引入而不是 @ import 的原因），src 会阻塞对文档的处理。</p></details><details class="details custom-block"><summary>iframe是什么？有哪些优缺点？</summary><p>iframe 可以在一个网站里面嵌入另一个网站的内容。</p><p>优点：</p><ul><li>iframe能够原封不动的把嵌入的网页展现出来。</li><li>如果有多个网页引用iframe，那么你只需要修改iframe的内容，就可以实现调用的每一个页面内容的更改，方便快捷。</li><li>网页如果为了统一风格，头部和版本都是一样的，就可以写成一个页面，用iframe来嵌套，可以增加代码的可重用。</li><li>如果遇到加载缓慢的第三方内容如图标和广告，这些问题可以由iframe来解决。</li></ul><p>缺点：</p><ul><li>会产生很多页面，不容易管理。</li><li>iframe框架结构有时会让人感到迷惑，如果框架个数多的话，可能会出现上下、左右滚动条，会分散访问者的注意力，用户体验度差。 * 代码复杂，无法被一些搜索引擎索引到，这一点很关键，现在的搜索引擎爬虫还不能很好的处理iframe中的内容，所以使用iframe会不利于搜索引擎优化。</li><li>很多的移动设备（PDA 手机）无法完全显示框架，设备兼容性差。</li><li>iframe 里面的样式、脚本资源，会增加请求次数，对于大型网站是不可取的。</li><li>iframe 会阻碍页面的 onload 事件，给用户页面加载很慢的感觉。</li></ul></details><details class="details custom-block"><summary>如何禁用a标签跳转页面或定位链接 ？</summary><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>&lt;a href=&quot;javascript:void(0);&quot; &gt;click&lt;/a&gt;</span></span>
<span class="line"><span>&lt;a href=&quot;javascript:;&quot; &gt;click&lt;/a&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;a href=&quot;&quot; onclick=&quot;return false;&quot;&gt;click&lt;/a&gt;</span></span>
<span class="line"><span>&lt;a href=&quot;#&quot; onclick=&quot;return false;&quot;&gt;click&lt;/a&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Event.preventDefault()</span></span>
<span class="line"><span></span></span>
<span class="line"><span>pointer-events: none;</span></span></code></pre></div></details><details class="details custom-block"><summary>script 标签中， async 和 defer 两个属性有什么用途和区别 ？</summary><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>&lt;script src=&#39;xxx&#39;&gt;&lt;/script&gt; // 顺序来加载并执行脚本, 阻塞后续的DOM渲染</span></span>
<span class="line"><span>&lt;script src=&#39;xxx&#39; async&gt;&lt;/script&gt; // 浏览器会异步下载该文件并且不会影响后续DOM的渲染</span></span>
<span class="line"><span>&lt;script src=&#39;xxx&#39; defer&gt;&lt;/script&gt; // 异步的加载并在允许的情况下执行, 没有顺序，谁先加载，谁先执行</span></span></code></pre></div></details><details class="details custom-block"><summary>常用的 meta 元素有哪些 ？</summary><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>&lt;meta charset=&quot;utf-8&quot;&gt;  // 编码格式</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;meta name=&quot;author&quot; content=&quot;qzjiang&quot;&gt; // 作者</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;meta name=&quot;keywords&quot; content=&quot;HTML, CSS, JavaScript&quot;&gt;  // 关键字</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;meta name=&quot;description&quot; content=&quot;My tutorials on HTML, CSS and JavaScript&quot;&gt; // 描述</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;meta name=&quot;viewport&quot; content=&quot;width=device-width, initial-scale=1.0, maximum-scale=1.0, minmum-scale=1.0&quot;&gt; // 页面视图属性</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;meta name=&quot;theme-color&quot; content=&quot;#222&quot;&gt;  // 主题色</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 请求和响应遵循的缓存机制，可以声明缓存的内容，修改过期时间，可多次声明</span></span>
<span class="line"><span>&lt;meta http-equiv=&quot;Cache-Control&quot; content=&quot;no-transform&quot;&gt;</span></span>
<span class="line"><span>&lt;meta http-equiv=&quot;Cache-Control&quot; content=&quot;no-siteapp&quot;&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 可以让网页成为一个富媒体对象，同意网页内容被其他网站引用，同时在应用的时候不会只是一个链接，会提取相应的信息展现给用户</span></span>
<span class="line"><span>&lt;meta property=&quot;og:type&quot; content=&quot;website&quot;&gt;</span></span>
<span class="line"><span>&lt;meta property=&quot;og:url&quot; content=&quot;https://zjgyb.github.io/index.html&quot;&gt;</span></span>
<span class="line"><span>&lt;meta property=&quot;og:site_name&quot; content=&quot;tony&#39;s blog&quot;&gt;</span></span></code></pre></div></details>`,35),e=[p];function i(o,c,u,d,m,r){return t(),a("div",null,e)}const b=s(n,[["render",i]]);export{h as __pageData,b as default};
